import { RepoType } from '../contract.js';

export const checkId = 'health-check';
export const name = 'Health Check Route';
export const appliesTo = ['deployable', 'server', 'framework'];

const HEALTH_LIBS = new Set([
  'lightship', 'terminus', 'express-actuator', 'under-pressure',
  '@nestjs/terminus', 'healthcheck-middleware', 'koa-healthcheck',
  'server-health', 'health-check', 'healthcheck', 'node-health-check',
]);

const SERVER_DEPS = new Set([
  'express', 'fastify', 'koa', 'hapi', '@hapi/hapi', 'micro', 'restify',
  'connect', 'polka', 'ws', 'socket.io', 'nitropack', 'nitro', 'h3',
  'hono', 'elysia', 'uwebsockets', '@nestjs/core', '@nestjs/common',
]);

const META_FRAMEWORKS = new Set([
  'next', 'nuxt', '@nuxt/core', 'astro', '@astrojs/node', 'remix', '@remix-run/node',
  '@remix-run/serve', '@sveltejs/kit', 'solid-start', '@solidjs/start',
]);

const EXCLUDED_PATH_RE = /(\/|^)(test|tests|__tests__|__mocks__|fixtures?|examples?|demo|demos|playground|benchmark|benchmarks|docs?|\.github|\.storybook|scripts?|tools?|dist|build|coverage|storybook|bin|cli|config|\.vscode|node_modules)(\/|$)/i;

const HEALTH_BASENAMES = new Set([
  'health', 'healthz', 'healthcheck', 'health-check', 'status', 'ping',
  'ready', 'readyz', 'readiness', 'alive', 'live', 'livez', 'liveness', 'up', 'heartbeat',
]);

const ROUTE_DIR_RE = /(^|\/)(api|pages\/api|app\/api|server\/api|server\/routes|routes|controllers|handlers|middleware|functions|workers|probes|internal\/.*\/http|cmd\/.*\/http)(\/|$)/i;

const HEALTH_CODE_PATTERNS = [
  /\.(get|post|put|delete|all|use|route)\s*\(\s*['"`]\/(api\/)?(healthz?|health[-_]?check|status|readyz?|readiness|alive|livez?|liveness|ping|up|heartbeat)\b/i,
  /pathname\s*===?\s*['"`]\/(api\/)?(healthz?|health[-_]?check|status|readyz?|readiness|alive|livez?|liveness|ping|up|heartbeat)\b/i,
  /new\s+URL\s*\([^)]*\)\.pathname\s*===?\s*['"`]\/(api\/)?(healthz?|status|readyz?|alive|ping|up)\b/i,
  /event\.(path|node\.req\.url|request\.url).*(health|status|ready|alive|ping)/i,
  /(defineEventHandler|eventHandler)\s*\(.*(health|status|ready|alive|ping)/i,
  /@Get\s*\(['"`](health|status|ready|alive|ping)['"`]\)/i,
  /@Controller\s*\(['"`](health|status|ready|alive|ping)['"`]\)/i,
  /lightship|terminus|under-pressure|express-actuator|@nestjs\/terminus|healthcheck-middleware|koa-healthcheck/i,
  /livenessProbe|readinessProbe|startupProbe/i,
  /json\s*\(\s*\{[^}]*status\s*:\s*['"`](ok|up|healthy|passing)['"`]/i,
];

function isExcludedPath(p) {
  return EXCLUDED_PATH_RE.test(p);
}

function getAllDeps(packageJson) {
  return {
    ...packageJson?.dependencies,
    ...packageJson?.devDependencies,
    ...packageJson?.peerDependencies,
    ...packageJson?.optionalDependencies,
  };
}

function hasProductionStartScript(packageJson) {
  if (!packageJson?.scripts) return false;
  const devCmd = /(scripts?\/|tools?\/|examples?\/|docs?\/|benchmark|bench|release|publish|generate|build|watch|dev(?![- ]?server)|preview|storybook|lint|test|tsc|typecheck|clean|webpack|rollup|gulp|grunt|babel|jest|vitest|eslint|knip|turbo\s+run\s+(build|test|lint))/i;
  const runtimeCmd = /(^|\s)(next|nuxi?|remix|astro|svelte-kit|solid-start)\s+(start|serve)\b|(^|\s)(node|bun|deno|pm2|serve|http-server)\s+[^&|;]*(server|app|main|dist|build|index)\.(js|mjs|cjs|ts)\b/i;

  for (const [name, cmd] of Object.entries(packageJson.scripts)) {
    if (name !== 'start' && !/^start:/i.test(name)) continue;
    if (!cmd || devCmd.test(cmd)) continue;
    if (runtimeCmd.test(cmd)) return true;
    if (/^start:prod(uction)?$/i.test(name) && !devCmd.test(cmd)) return true;
  }
  return false;
}

function hasHealthDependency(packageJson) {
  if (!packageJson) return null;
  const deps = getAllDeps(packageJson);
  return Object.keys(deps).find(d => HEALTH_LIBS.has(d)) || null;
}

function healthScriptName(packageJson) {
  if (!packageJson?.scripts) return null;
  for (const name of Object.keys(packageJson.scripts)) {
    if (/^(health|healthcheck|health-check|status|ping|ready|readiness|alive|liveness)(:|$)/i.test(name)) return name;
  }
  return null;
}

function hasStrongDeploymentConfig(tree) {
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    const l = p.toLowerCase();
    return l === 'dockerfile' || l.startsWith('dockerfile.') ||
      /(^|\/)docker-compose\.(yml|yaml)$/i.test(p) ||
      /(^|\/)fly\.toml$/i.test(p) ||
      /(^|\/)render\.yaml$/i.test(p) ||
      /(^|\/)railway\.(toml|json)$/i.test(p) ||
      /(^|\/)Procfile$/i.test(p) ||
      /(^|\/)k8s\//i.test(p) ||
      /(^|\/)kubernetes\//i.test(p) ||
      /(^|\/)helm\//i.test(p);
  });
}

function hasWeakPlatformConfig(tree) {
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    const l = p.toLowerCase();
    return l === 'vercel.json' || l === 'netlify.toml' || l === 'wrangler.toml' ||
      l === 'wrangler.json' || l === 'app.yaml' || l === 'serverless.yml' ||
      l === 'serverless.yaml' || l === 'serverless.json';
  });
}

function looksLikeHealthPath(p) {
  if (isExcludedPath(p)) return false;
  if (!/\.(js|ts|mjs|cjs|jsx|tsx|go|py|rs|java|rb|php)$/i.test(p)) return false;
  const parts = p.split('/');
  const base = parts[parts.length - 1].replace(/\.[^.]+$/, '').toLowerCase();
  const parent = parts[parts.length - 2]?.toLowerCase() || '';
  const routeLike = ROUTE_DIR_RE.test(p) || /(^|\/)app\/[^/]+\/route\.(js|ts|jsx|tsx)$/i.test(p) || /(^|\/)pages\/api\//i.test(p);
  if (!routeLike && parts.length > 2) return false;
  if (HEALTH_BASENAMES.has(base)) return true;
  if (parent === 'health' || parent === 'status' || parent === 'ping' || parent === 'ready') {
    return /^(index|route|\+server|main|handler)$/.test(base);
  }
  return false;
}

function findHealthPath(tree) {
  return tree.find(looksLikeHealthPath) || null;
}

function hasApiArtifacts(tree) {
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    return /(^|\/)pages\/api\/[^/]+\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)app\/api\/.*\/route\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)src\/app\/api\/.*\/route\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)api\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) ||
      /(^|\/)server\/api\/[^/]+\.(js|ts|mjs|cjs)$/i.test(p) ||
      /(^|\/)routes\/api\/[^/]+\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p) ||
      /(^|\/)functions\/[^/]+\.(js|ts|mjs|cjs)$/i.test(p) ||
      /(^|\/)workers?\/[^/]+\.(js|ts|mjs|cjs)$/i.test(p);
  });
}

function hasCustomServerEntry(tree, packageJson) {
  const deps = getAllDeps(packageJson);
  const hasServerDep = Object.keys(deps).some(d => SERVER_DEPS.has(d));
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    if (/^(src\/)?(server|app|main)\.(js|ts|mjs|cjs)$/i.test(p)) return true;
    if (/^(src\/)?index\.(js|ts|mjs|cjs)$/i.test(p) && hasServerDep && hasProductionStartScript(packageJson)) return true;
    return false;
  });
}

function hasFrameworkApp(tree) {
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    return /(^|\/)pages\/[^/]+\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)app\/[^/]+\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)src\/pages\/[^/]+\.(js|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)src\/app\/[^/]+\.(js|ts|jsx|tsx)$/i.test(p);
  });
}

function hasFrameworkConfig(tree) {
  return tree.some(p => {
    if (isExcludedPath(p)) return false;
    return /(^|\/)next\.config\.(js|mjs|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)nuxt\.config\.(ts|js)$/i.test(p) ||
      /(^|\/)astro\.config\.(mjs|js|ts)$/i.test(p) ||
      /(^|\/)remix\.config\.(js|ts)$/i.test(p) ||
      /(^|\/)svelte\.config\.(js|ts)$/i.test(p);
  });
}

function isFrameworkSource(tree, packageJson) {
  if (hasStrongDeploymentConfig(tree) || hasProductionStartScript(packageJson)) return false;
  const pkgCount = tree.filter(p => /^packages\/[^/]+\/package\.json$/i.test(p) && !isExcludedPath(p)).length;
  const hasApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p) && !isExcludedPath(p));
  if (pkgCount >= 3 && !hasApps) return true;
  if (pkgCount >= 2 && !hasApps && packageJson?.private && (packageJson?.workspaces || tree.some(p => /^pnpm-workspace\.yaml$/i.test(p)))) return true;
  const exampleCount = tree.filter(p => /^examples?\/[^/]+\//i.test(p)).length;
  return exampleCount >= 3 && !hasApps;
}

function isTutorialRepo(tree, packageJson) {
  if (hasStrongDeploymentConfig(tree) || hasProductionStartScript(packageJson)) return false;
  const text = `${packageJson?.name || ''} ${packageJson?.description || ''}`.toLowerCase();
  if (/\b(learn|tutorial|course|how[- ]?to|playground|starter[- ]?template|getting[- ]?started|training|workshop|bootcamp|walkthrough)\b/.test(text)) return true;
  const dirs = ['examples', 'example', 'starters', 'starter', 'templates', 'template', 'demos', 'demo', 'playground', 'learn', 'chapters', 'lessons', 'tutorial', 'tutorials', 'course', 'workshop', 'exercises', 'solutions'];
  let count = 0;
  for (const d of dirs) {
    count += tree.filter(p => new RegExp(`^${d}/[^/]+/package\\.json$`, 'i').test(p)).length;
  }
  return count >= 2;
}

function isBuildOrCliTool(packageJson) {
  if (!packageJson) return false;
  if (packageJson.bin || packageJson.directories?.bin) return true;
  const text = `${packageJson.name || ''} ${(packageJson.keywords || []).join(' ')}`.toLowerCase();
  return /\b(monorepo|build[- ]?tool|bundler|compiler|task[- ]?runner|orchestrator|cli[- ]?tool)\b/.test(text);
}

function isPureLibrary(tree, packageJson) {
  if (!packageJson) return false;
  if (hasStrongDeploymentConfig(tree) || hasProductionStartScript(packageJson)) return false;
  if (hasApiArtifacts(tree) || hasCustomServerEntry(tree, packageJson) || hasFrameworkApp(tree)) return false;
  const hasWorkspaceApps = tree.some(p => /^(apps|services|workers)\/[^/]+\/package\.json$/i.test(p) && !isExcludedPath(p));
  if (hasWorkspaceApps) return false;
  return !!(packageJson.exports || packageJson.main || packageJson.module || packageJson.types || packageJson.browser);
}

async function isStaticExport(tree, files) {
  const configs = tree.filter(p =>
    !isExcludedPath(p) && (
      /(^|\/)next\.config\.(js|mjs|ts|jsx|tsx)$/i.test(p) ||
      /(^|\/)astro\.config\.(mjs|js|ts)$/i.test(p) ||
      /(^|\/)nuxt\.config\.(ts|js)$/i.test(p) ||
      /(^|\/)svelte\.config\.(js|ts)$/i.test(p)
    )
  ).slice(0, 3);
  for (const cf of configs) {
    const content = await files.get(cf);
    if (!content) continue;
    if (/output\s*:\s*['"`](export|static)['"`]/.test(content)) return true;
    if (/ssr\s*:\s*false/.test(content)) return true;
    if (/target\s*:\s*['"`]static['"`]/.test(content)) return true;
    if (/adapter\s*:\s*static/.test(content)) return true;
  }
  return false;
}

function scoreServerFile(path) {
  let score = 0;
  if (/\.(test|spec)\./i.test(path) || isExcludedPath(path)) return -100;
  if (/^(src\/)?(server|app|main)\.(js|ts|mjs|cjs)$/i.test(path)) score += 16;
  else if (/(^|\/)(pages\/api|app\/api|server\/api|api\/|functions\/|workers?\/)/i.test(path)) score += 13;
  else if (/(^|\/)(controllers|handlers|routes|middleware|server)\//i.test(path)) score += 9;
  else if (/\.(route|router|controller|handler|endpoint|middleware)\./i.test(path)) score += 6;
  else if (/\.(js|ts|mjs|cjs)$/i.test(path)) score += 2;
  if (path.startsWith('src/')) score += 2;
  if (/(^|\/)components?\/|(^|\/)ui\/|(^|\/)widgets?\//i.test(path)) score -= 8;
  if (/(^|\/)pages\/(?!api\/)/i.test(path)) score -= 8;
  if (/(^|\/)app\/(?!api\/).*\/page\.(jsx|tsx)$/i.test(path)) score -= 8;
  if (path.split('/').length > 8) score -= 4;
  return score;
}

async function scanWorkspacePackages(tree, files) {
  const pkgPaths = tree
    .filter(p => /(^|\/)package\.json$/i.test(p) && p !== 'package.json' && !isExcludedPath(p))
    .slice(0, 16);

  let deployableWorkspace = false;
  for (const p of pkgPaths) {
    const content = await files.get(p);
    if (!content) continue;
    try {
      const pkg = JSON.parse(content);
      const lib = hasHealthDependency(pkg);
      if (lib) return { pass: { file: p, issue: `Uses ${lib}` }, deployableWorkspace };
      const script = healthScriptName(pkg);
      if (script) return { pass: { file: p, issue: `Script "${script}"` }, deployableWorkspace };

      const dir = p.slice(0, -'/package.json'.length);
      const deps = getAllDeps(pkg);
      const hasServerishDep = Object.keys(deps).some(d => SERVER_DEPS.has(d) || META_FRAMEWORKS.has(d));
      if (hasProductionStartScript(pkg) && hasServerishDep) {
        const prefix = `${dir}/`;
        const hasArtifacts = tree.some(f => f.startsWith(prefix) && !isExcludedPath(f) && (
          /(^|\/)(api|pages\/api|app\/api|server\/api|routes|functions|workers?)\//i.test(f.slice(prefix.length)) ||
          /^(server|app|main)\.(js|ts|mjs|cjs)$/i.test(f.slice(prefix.length))
        ));
        if (hasArtifacts) deployableWorkspace = true;
      }
    } catch (e) {
      // Ignore malformed workspace package.json files.
    }
  }
  return { pass: null, deployableWorkspace };
}

export async function check(context) {
  const { tree, files, packageJson, repoType } = context;

  try {
    const healthPath = findHealthPath(tree);
    if (healthPath) {
      return { checkId, status: 'pass', confidence: 'high', message: `Health endpoint file found: ${healthPath}`, findings: [{ file: healthPath, issue: 'Health route file detected' }] };
    }

    const healthLib = hasHealthDependency(packageJson);
    if (healthLib) {
      return { checkId, status: 'pass', confidence: 'high', message: `Health check library present: ${healthLib}`, findings: [{ file: 'package.json', issue: `Uses ${healthLib}` }] };
    }

    const script = healthScriptName(packageJson);
    if (script) {
      return { checkId, status: 'pass', confidence: 'high', message: `Health check script found: "${script}"`, findings: [{ file: 'package.json', issue: `Script "${script}" indicates health monitoring` }] };
    }

    const dockerfile = tree.find(p => !isExcludedPath(p) && (/(^|\/)dockerfile$/i.test(p) || /(^|\/)dockerfile\./i.test(p)));
    if (dockerfile) {
      const content = await files.get(dockerfile);
      if (content && /^\s*HEALTHCHECK\b/im.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `HEALTHCHECK instruction in ${dockerfile}`, findings: [{ file: dockerfile, issue: 'Docker HEALTHCHECK found' }] };
      }
    }

    const composeFile = tree.find(p => !isExcludedPath(p) && /(^|\/)docker-compose\.(yml|yaml)$/i.test(p));
    if (composeFile) {
      const content = await files.get(composeFile);
      if (content && /healthcheck\s*:/i.test(content)) {
        return { checkId, status: 'pass', confidence: 'high', message: `Health check in ${composeFile}`, findings: [{ file: composeFile, issue: 'Docker Compose healthcheck found' }] };
      }
    }

    const k8sFiles = tree.filter(p => !isExcludedPath(p) && (/(^|\/)k8s\//i.test(p) || /(^|\/)kubernetes\//i.test(p) || /(^|\/)helm\//i.test(p)));
    for (const f of k8sFiles.slice(0, 3)) {
      const content = await files.get(f);
      if (content && (/(liveness|readiness|startup)Probe\s*:/i.test(content) || /path:\s*["']?\/(health|status|ready|alive|ping)/i.test(content))) {
        return { checkId, status: 'pass', confidence: 'high', message: `K8s health probe in ${f}`, findings: [{ file: f, issue: 'Kubernetes probe detected' }] };
      }
    }

    const platformHealthConfigs = [
      { pattern: /(^|\/)fly\.toml$/i, re: /http_checks|healthcheck|path\s*=\s*["']\/(health|status|ping)/i },
      { pattern: /(^|\/)app\.yaml$/i, re: /health_check|readiness_check|liveness_check|\/health/i },
      { pattern: /(^|\/)render\.yaml$/i, re: /healthCheckPath|\/health/i },
    ];
    for (const { pattern, re } of platformHealthConfigs) {
      const file = tree.find(p => !isExcludedPath(p) && pattern.test(p));
      if (file) {
        const content = await files.get(file);
        if (content && re.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health check config in ${file}`, findings: [{ file, issue: 'Platform health check configured' }] };
        }
      }
    }

    const workspace = await scanWorkspacePackages(tree, files);
    if (workspace.pass) {
      return { checkId, status: 'pass', confidence: 'high', message: `Health check configuration in ${workspace.pass.file}`, findings: [workspace.pass] };
    }

    const fileCount = tree.filter(p => !p.endsWith('/')).length;
    if (fileCount < 3) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Empty or minimal repository', findings: [] };
    }

    if (repoType === RepoType.LIBRARY || repoType === RepoType.EMPTY || repoType === RepoType.TOOL) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library, empty, or tool repository', findings: [] };
    }

    if (isFrameworkSource(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Framework or library source code', findings: [] };
    }

    if (isTutorialRepo(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Tutorial, course, or examples repository', findings: [] };
    }

    if (isBuildOrCliTool(packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Build tool, CLI, or task runner', findings: [] };
    }

    if (isPureLibrary(tree, packageJson)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Library package without server or deployment signals', findings: [] };
    }

    if (await isStaticExport(tree, files)) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Static site export detected; health check not required', findings: [] };
    }

    const serverFiles = tree
      .filter(p => /\.(js|ts|mjs|cjs|jsx|tsx)$/i.test(p))
      .map(p => ({ path: p, score: scoreServerFile(p) }))
      .filter(f => f.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 12)
      .map(f => f.path);

    for (const file of serverFiles) {
      const content = await files.get(file);
      if (!content) continue;
      for (const pattern of HEALTH_CODE_PATTERNS) {
        if (pattern.test(content)) {
          return { checkId, status: 'pass', confidence: 'high', message: `Health endpoint found in ${file}`, findings: [{ file, issue: 'Health route or probe detected' }] };
        }
      }
    }

    const deps = getAllDeps(packageJson);
    const depList = Object.keys(deps);
    const hasServerDep = depList.some(d => SERVER_DEPS.has(d));
    const hasMetaFramework = depList.some(d => META_FRAMEWORKS.has(d)) || hasFrameworkConfig(tree);
    const productionStart = hasProductionStartScript(packageJson);
    const strongDeploy = hasStrongDeploymentConfig(tree);
    const apiArtifacts = hasApiArtifacts(tree);
    const customServer = hasCustomServerEntry(tree, packageJson);
    const frameworkApp = hasFrameworkApp(tree);

    if ((strongDeploy && (apiArtifacts || customServer || productionStart || workspace.deployableWorkspace)) ||
        ((apiArtifacts || customServer || workspace.deployableWorkspace) && (productionStart || hasServerDep))) {
      return {
        checkId,
        status: 'fail',
        confidence: 'high',
        message: 'Deployable server detected but no health check endpoint found',
        findings: serverFiles.length > 0
          ? serverFiles.slice(0, 3).map(f => ({ file: f, issue: 'Server file scanned, no health endpoint found' }))
          : [{ file: 'package.json', issue: 'Runtime server signals present, but no health endpoint was found' }],
      };
    }

    if (hasWeakPlatformConfig(tree) && !hasMetaFramework && !productionStart && !apiArtifacts && !customServer) {
      return { checkId, status: 'not-applicable', confidence: 'high', message: 'Platform-managed static deployment; health check not required', findings: [] };
    }

    if ((hasMetaFramework && productionStart && frameworkApp) || serverFiles.length > 0 || (hasServerDep && productionStart)) {
      const findings = serverFiles.length > 0
        ? serverFiles.slice(0, 3).map(f => ({ file: f, issue: 'Server-like file found, but deployment intent is ambiguous' }))
        : [{ file: 'package.json', issue: 'Framework app with a production start script, but no dedicated API/server routes were found' }];
      return {
        checkId,
        status: 'check-it',
        confidence: 'medium',
        message: 'Web server or framework app detected; verify whether this deployment requires an explicit health endpoint',
        findings,
      };
    }

    return { checkId, status: 'not-applicable', confidence: 'medium', message: 'No server or deployable signals detected; health check not required', findings: [] };
  } catch (err) {
    console.error('[health-check] Error:', err);
    return { checkId, status: 'not-applicable', confidence: 'low', message: `Analysis error: ${err.message}`, findings: [] };
  }
}
